example.code:
use std::sync::Arc;

let counter = Arc::new(Mutex::new(0u64));
let counter2 = Arc::clone(&counter);  // O(1) clone — increments refcount

tokio::spawn(async move {
    *counter2.lock().unwrap() += 1;
});

use std::borrow::Cow;

fn sanitize(input: &str) -> Cow<str> {
    if input.contains("badword") {
        Cow::Owned(input.replace("badword", "***"))
    } else {
        Cow::Borrowed(input)  // no allocation when clean
    }
}
